  async function executeChain(ctx: ExtensionContext, chain: Array<{ role: SubagentRoleName; task: string; name?: string; cwd?: string; modelOverride?: string }>, onUpdate?: any) {
    const fleetId = makeId("fleet");
    const results: PersistedRunRecord[] = [];
    let previous = "";
    for (const step of chain) {
      const task = step.task.replace(/\{previous\}/g, previous);
      const result = await executeRun(ctx, { ...step, task, mode: "chain", fleetId }, onUpdate);
      results.push(result);
      await emitProgress(onUpdate, `Chain step ${results.length}/${chain.length}`, results);
      if (result.status !== "done") break;
      previous = result.summary || previous;
