    renderCall(args: any, theme: any) {
      const mode = args.mode || "single";
      if (mode === "single") {
        return new Text(`${theme.fg("toolTitle", theme.bold("subagent "))}${theme.fg("accent", args.role || "role")} ${theme.fg("dim", truncate(args.task || "", 80))}`, 0, 0);
      }
      if (mode === "parallel") {
        return new Text(`${theme.fg("toolTitle", theme.bold("subagent "))}${theme.fg("accent", `parallel (${(args.tasks || []).length})`)}`, 0, 0);
      }
      return new Text(`${theme.fg("toolTitle", theme.bold("subagent "))}${theme.fg("accent", `chain (${(args.chain || []).length})`)}`, 0, 0);
    },
    renderResult(result: any, _options: any, theme: any) {
      const text = result?.content?.[0]?.text || "";
      return new Text(theme.fg(result?.isError ? "error" : "muted", text), 0, 0);
    }
  });
}

import type { AgentSessionEvent, SessionStats as AgentSessionStats } from "@mariozechner/pi-coding-agent";
import { createAgentSession, DefaultResourceLoader, SessionManager, createCodingTools, createReadOnlyTools } from "@mariozechner/pi-coding-agent";
import type { Model } from "@mariozechner/pi-ai";
import { extractText } from "./rpc.js";

export type SessionStats = AgentSessionStats;

export interface SessionSubagentOptions {
  cwd: string;
  sessionDir: string;
  model: string;
  builtins: string[];
  extensionPaths?: string[];
  onEvent?: (event: AgentSessionEvent) => void | Promise<void>;
  parentModel?: Model<any>;
  modelRegistry?: {
    getAvailable(): Model<any>[];
  };
}

function resolveModel(options: SessionSubagentOptions): Model<any> | undefined {
  const available = options.modelRegistry?.getAvailable() || [];
  const exactId = available.find((model) => model.id === options.model);
  if (exactId) return exactId;
  const namespaced = available.find((model) => `${model.provider}/${model.id}` === options.model);
  if (namespaced) return namespaced;
  if (options.parentModel && options.parentModel.id === options.model) return options.parentModel;
  return options.parentModel;
}

function createTools(cwd: string, builtins: string[]) {
  const readOnly = ["read", "grep", "find", "ls"];
  const coding = ["read", "bash", "edit", "write"];
  const wantsCoding = builtins.some((name) => coding.includes(name));
  const base = wantsCoding ? createCodingTools(cwd) : createReadOnlyTools(cwd);
  const byName = new Map(base.map((tool) => [tool.name, tool] as const));
  const ordered = builtins.map((name) => byName.get(name)).filter((tool): tool is NonNullable<typeof tool> => Boolean(tool));
  return ordered.length > 0 ? ordered : base;
}

export class AgentSessionSubagentProcess {
  readonly cwd: string;
  readonly sessionDir: string;
  readonly model: string;
  readonly builtins: string[];
  readonly extensionPaths: string[];
  sessionFile?: string;
  sessionId?: string;
  latestAssistantText = "";
  latestTool = "";
  lastEventAt = Date.now();

  private session?: Awaited<ReturnType<typeof createAgentSession>>["session"];
  private unsubscribe?: () => void;

  constructor(private readonly options: SessionSubagentOptions) {
    this.cwd = options.cwd;
    this.sessionDir = options.sessionDir;
    this.model = options.model;
    this.builtins = options.builtins;
    this.extensionPaths = options.extensionPaths || [];
  }

  async initialize() {
    const resourceLoader = new DefaultResourceLoader({
      cwd: this.cwd,
      additionalExtensionPaths: this.extensionPaths,
    });
    await resourceLoader.reload();

    const { session } = await createAgentSession({
      cwd: this.cwd,
      model: resolveModel(this.options),
      tools: createTools(this.cwd, this.builtins),
      resourceLoader,
      sessionManager: SessionManager.create(this.cwd, this.sessionDir),
    });

    this.session = session;
    this.sessionFile = session.sessionFile;
    this.sessionId = session.sessionId;
    this.unsubscribe = session.subscribe((event) => {
      this.lastEventAt = Date.now();
      if (event.type === "message_update") {
        const update = event.assistantMessageEvent;
        if (update.type === "text_delta") {
          this.latestAssistantText += update.delta || "";
        } else if (update.type === "text_start") {
          const part = update.partial.content[update.contentIndex];
          this.latestAssistantText = part?.type === "text" ? part.text : this.latestAssistantText;
        } else if (update.type === "text_end") {
          this.latestAssistantText = update.content || this.latestAssistantText;
        }
      }
      if (event.type === "message_end" && event.message.role === "assistant") {
        const text = extractText(event.message.content);
        if (text.trim()) this.latestAssistantText = text;
      }
      if (event.type === "tool_execution_start") {
        this.latestTool = event.toolName || "tool";
      }
      void this.options.onEvent?.(event);
    });

    return this.getState();
  }

  async prompt(message: string) {
    if (!this.session) throw new Error("Subagent session not initialized");
    await this.session.prompt(message);
  }

  async steer(message: string) {
    if (!this.session) throw new Error("Subagent session not initialized");
    await this.session.steer(message);
  }

  async followUp(message: string) {
    if (!this.session) throw new Error("Subagent session not initialized");
    await this.session.followUp(message);
  }

  async abort() {
    if (!this.session) return false;
    await this.session.abort();
    return true;
  }

  async getState() {
    if (!this.session) throw new Error("Subagent session not initialized");
    this.sessionFile = this.session.sessionFile;
    this.sessionId = this.session.sessionId;
    return {
      sessionFile: this.session.sessionFile,
      sessionId: this.session.sessionId,
      isStreaming: this.session.isStreaming,
      pendingMessageCount: 0,
      messageCount: this.session.messages.length,
    };
  }

  getMessagesSync(): any[] {
    return this.session?.messages ? [...this.session.messages] : [];
  }

  async getMessages() {
    return this.getMessagesSync();
  }

  async getSessionStats(): Promise<SessionStats> {
    if (!this.session) throw new Error("Subagent session not initialized");
    return this.session.getSessionStats();
  }

  async waitForQuiescence(timeoutMs = 30 * 60 * 1000) {
    if (!this.session) throw new Error("Subagent session not initialized");
    const startedAt = Date.now();
    while (Date.now() - startedAt < timeoutMs) {
      const state = await this.getState();
      if (!state.isStreaming) return state;
      await new Promise((resolve) => setTimeout(resolve, 100));
    }
    throw new Error(`Timed out waiting for subagent quiescence after ${Math.round(timeoutMs / 1000)}s`);
  }

  async forceTerminate() {
    if (!this.session) return;
    await this.session.abort();
    this.shutdown();
  }

  async shutdown() {
    this.unsubscribe?.();
    this.unsubscribe = undefined;
    this.session?.dispose();
    this.session = undefined;
  }
}

