					accountId,
					query: args.query,
					purpose: args.purpose,
					timeoutMs: args.timeoutMs,
					baseUrl: model.baseUrl,
			  })
			: await runAnthropicSearch({
					model: model.id,
					apiKey,
					query: args.query,
					purpose: args.purpose,
					timeoutMs: args.timeoutMs,
			  });

	if (args.json) {
		console.log(
			JSON.stringify(
				{
					provider,
					model: model.id,
					query: args.query,
					purpose: args.purpose,
					result: text,
				},
				null,
				2,
			),
		);
		return;
	}

	console.log(`Provider: ${provider}`);
	console.log(`Model: ${model.id}`);
	console.log("");
	console.log(text);
}

main().catch((err) => {
	console.error(`Error: ${err?.message || err}`);
