function isAssistantMessage(message: TranscriptMessage): message is AssistantMessage {
  return message.role === "assistant";
}

function isUserMessage(message: TranscriptMessage): message is UserMessage {
  return message.role === "user";
}

function isToolResultMessage(message: TranscriptMessage): message is ToolResultMessage {
  return message.role === "toolResult";
}

function isToolCall(part: unknown): part is ToolCall {
  return Boolean(part && typeof part === "object" && "type" in part && (part as { type?: unknown }).type === "toolCall");
}

function isTextPart(part: unknown): part is TextContent {
  return Boolean(part && typeof part === "object" && "type" in part && (part as { type?: unknown }).type === "text" && "text" in part);
}

function normalizeText(text: string, fallback = ""): string {
  const normalized = text.replace(/\s+/g, " ").trim();
  return normalized || fallback;
}

function compactJson(value: unknown): string {
  try {
    return JSON.stringify(value);
  } catch {
    return String(value);
  }
}

function formatTokenCount(tokens: number): string {
  if (tokens >= 1_000_000) return `${(tokens / 1_000_000).toFixed(1)}m`;
  if (tokens >= 1_000) return `${(tokens / 1_000).toFixed(1)}k`;
  return `${tokens}`;
}

